var b="url",c="单仓驾驶舱.html",d="generationDate",e=new Date(1781494425747.68),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="8593d7e384404653b9411bfaf1a9632c",v="type",w="Axure:Page",x="单仓驾驶舱",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="5dd06df257904eee9226174138cdbf31",E="label",F="物料库存",G="说明",H="<p><span>1.数据源：[仓库管理&gt;&gt;物料库存：库存汇总]中'仓库'与当前指定仓库一致的数据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.字段值：清单中同名字段</span></p><p><span>2.固定高度，超过高度行，5S滚动展示</span></p>",I="2",J="811e793e81224b13bae4dfe15d8fd4c2",K="类别库存",L="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#333333;\">圆角环形图</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#D9001B;\">以物料的“一级类别”为维度进行轮播</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; 1.1 仅对存在库存的'一级类别'进行轮播</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; 1.2 轮播速度：5S</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.数据源：[仓库管理&gt;&gt;物料库存：库存汇总]中</span><span>'仓库'与当前指定仓库一致的数据</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; 2.1 将库存按物料所属'一级类别'进行汇总</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; 2.2 统计'一级类别'下&quot;实际库存&quot;数量排</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">前10</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">的物料</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 2.2.1 无关规格、颜色</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">3.鼠标放置：展示 “物料名称”、“汇总该物料的实际库存”、“物料单位”、“该物料的实际库存在前10物料库存中的占比”</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; 3.1 例：双面胶朴纸 500 条&nbsp; 21.6%</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"><br></span></p><p><span style=\"color:#333333;\">样式图：</span><span style=\"color:#D9001B;\">https://echarts.apache.org/examples/zh/editor.html?c=pie-borderRadius</span></p>",M="3",N="db92a79f05b04aa8badd84d74b0ac948",O="当日入库日志",P="<p><span>1.在[物料库存日志&gt;&gt;汇总日志]中满足下述全部条件的数据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.“执行单号”前缀为'RKD'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.“仓库”与当前指定仓库一致</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.“操作时间”为当日</span></p><p><span>2.表单描述</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.'时间'格式为“时：分”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.固定高度，超过高度行，5S滚动展示</span></p>",Q="4",R="4d283c39cfef4878b343c61d138966c5",S="当日出库日志",T="<p><span>1.在[物料库存日志&gt;&gt;汇总日志]中满足下述全部条件的数据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.“执行单号”前缀为'CKD'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.“仓库”与当前指定仓库一致</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.“操作时间”为当日</span></p><p><span>2.表单描述</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.'数量'数值均为绝对值，展示正数</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.'时间'格式为“时：分”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.固定高度，超过高度行，5S滚动展示</span></p>",U="style",V="baseStyle",W="627587b6038d43cca051c114ac41ad32",X="pageAlignment",Y="center",Z="fill",ba="fillType",bb="solid",bc="color",bd=0xFFFFFFFF,be="image",bf="imageAlignment",bg="near",bh="imageRepeat",bi="auto",bj="favicon",bk="sketchFactor",bl="0",bm="colorStyle",bn="appliedColor",bo="fontName",bp="Applied Font",bq="borderWidth",b